-- 기존 데이터 삭제
DELETE FROM attendance_records;
DELETE FROM members;
DELETE FROM discipleship_classes;

-- 제자반 생성

-- 회원 등록
DO $$ DECLARE
  cls_양선반 UUID;
  cls_온유반 UUID;
  cls_인내절제반 UUID;
  cls_화평반 UUID;
  cls_충성희락반 UUID;
  cls_사랑반 UUID;
BEGIN
  SELECT id INTO cls_양선반 FROM discipleship_classes WHERE name = '양선반';
  SELECT id INTO cls_온유반 FROM discipleship_classes WHERE name = '온유반';
  SELECT id INTO cls_인내절제반 FROM discipleship_classes WHERE name = '인내절제반';
  SELECT id INTO cls_화평반 FROM discipleship_classes WHERE name = '화평반';
  SELECT id INTO cls_충성희락반 FROM discipleship_classes WHERE name = '충성희락반';
  SELECT id INTO cls_사랑반 FROM discipleship_classes WHERE name = '사랑반';

END $$;
